// Parse Alertmanager webhook payload
const body = $input.first().json;
const alerts = body.alerts || [];

const parsed = alerts.map(alert => ({
  alertname: alert.labels?.alertname || 'unknown',
  severity:  alert.labels?.severity  || 'unknown',
  category:  alert.labels?.category  || 'unknown',
  instance:  alert.labels?.instance  || 'unknown',
  job:       alert.labels?.job       || 'unknown',
  status:    alert.status            || 'unknown',
  startsAt:  alert.startsAt          || new Date().toISOString(),
  endsAt:    alert.endsAt            || '',
  summary:   alert.annotations?.summary     || '',
  description: alert.annotations?.description || '',
  generatorURL: alert.generatorURL   || ''
}));

// Only process firing alerts
const firing = parsed.filter(a => a.status === 'firing');

if (firing.length === 0) {
  return [{ json: { skip: true, reason: 'No firing alerts' } }];
}

// Build a combined summary for Ollama
const alertsSummary = firing.map(a =>
  `• [${a.severity.toUpperCase()}] ${a.alertname} on ${a.instance}: ${a.summary}\n  ${a.description}`
).join('\n\n');

return [{ json: { alerts: firing, alertsSummary, count: firing.length, skip: false } }];

// Combine context from Prometheus and the alert payload
// Note: in a real multiplex merge the items arrive in pairs;
// we grab available context gracefully.
const alertItem = $('Parse Alert Payload').first().json;
const cpuData = $('Query Prometheus Context').first()?.json;
const memData = $('Query Memory').first()?.json;

const cpuValue = cpuData?.data?.result?.[0]?.value?.[1] || 'N/A';
const memValue = memData?.data?.result?.[0]?.value?.[1] || 'N/A';

const cpuPct  = cpuValue !== 'N/A' ? parseFloat(cpuValue).toFixed(1) + '%' : 'N/A';
const memPct  = memValue !== 'N/A' ? parseFloat(memValue).toFixed(1) + '%' : 'N/A';

const now = new Date().toISOString();

const prompt = `You are an SRE (Site Reliability Engineer) assistant. Analyze the following Prometheus alerts and provide:
1. A concise root-cause hypothesis (2-3 sentences)
2. Immediate recommended actions (bullet list)
3. Long-term prevention measures (bullet list)
4. Estimated impact and urgency (1 sentence)

Current system state:
- CPU usage: ${cpuPct}
- Memory usage: ${memPct}
- Timestamp: ${now}

Firing alerts (${alertItem.count}):
${alertItem.alertsSummary}

Respond in a structured, concise format. Be specific and actionable.`;

return [{ json: { prompt, alerts: alertItem.alerts, cpuPct, memPct, now } }];

const ollamaResponse = $input.first().json;
const promptCtx = $('Build Ollama Prompt').first().json;

const aiText = ollamaResponse?.response || 'AI analysis unavailable';
const alertNames = promptCtx.alerts.map(a => a.alertname).join(', ');
const severity = promptCtx.alerts.reduce((max, a) =>
  a.severity === 'critical' ? 'critical' : max, 'warning');

const severityEmoji = severity === 'critical' ? '🔴' : '🟡';

const text = `${severityEmoji} **AI Alert Analysis** — ${alertNames}\n\n` +
  `**System State:** CPU ${promptCtx.cpuPct} | Memory ${promptCtx.memPct}\n\n` +
  `---\n\n${aiText}`;

const tags = ['ai-analysis', 'alert', severity, ...promptCtx.alerts.map(a => a.alertname)];

return [{
  json: {
    text,
    tags,
    time: new Date().getTime(),
    timeEnd: new Date().getTime() + 300000
  }
}];
